(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"customer-lifetime-value",fields:[{"key":"avgOrder","label":"평균 구매금액","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"purchasesPerYear","label":"연간 구매횟수","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"grossMargin","label":"매출총이익률 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"years","label":"평균 유지기간 (년)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"acquisitionCost","label":"고객획득비용","type":"number","placeholder":"","default":"0","options":[],"raw":false}],hint:"단순 추정 모델이며 할인율·재구매 확률 변화는 반영하지 않습니다.",compute:function(x){var a=Number(x.avgOrder),f=Number(x.purchasesPerYear),m=Number(x.grossMargin)/100,y=Number(x.years),c=Number(x.acquisitionCost);if(![a,f,m,y,c].every(Number.isFinite)||a<0||f<0||m<0||m>1||y<0||c<0)return{error:"금액·횟수·기간은 0 이상, 이익률은 0~100%로 입력해 주세요."};var revenue=a*f*y,gross=revenue*m;return{revenue:revenue,grossValue:gross,netValue:gross-c};},format:function(r,api){return api.resultCard("예상 순 고객가치",api.formatWon(r.netValue),"")+api.resultCard("예상 총 매출",api.formatWon(r.revenue),"")+api.resultCard("마진 반영 고객가치",api.formatWon(r.grossValue),"");}},{id:"customer-churn-rate",fields:[{"key":"startCustomers","label":"기간 시작 고객 수","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"lostCustomers","label":"기간 중 이탈 고객 수","type":"integer","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var s=Number(x.startCustomers),l=Number(x.lostCustomers);if(!Number.isInteger(s)||!Number.isInteger(l)||s<=0||l<0||l>s)return{error:"시작 고객 수는 1 이상의 정수이며 이탈 고객 수는 시작 고객 수 이하여야 합니다."};return{rate:l/s*100,remaining:s-l};},format:function(r,api){return api.resultCard("고객 이탈률",api.formatNumber(r.rate,4)+"%","")+api.resultCard("남은 고객 수",api.formatNumber(r.remaining,0)+"명","");}},{id:"monthly-recurring-revenue",fields:[{"key":"customers","label":"활성 구독 고객 수","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"arpu","label":"고객당 월평균 매출","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var c=Number(x.customers),a=Number(x.arpu);if(!Number.isInteger(c)||c<0||!Number.isFinite(a)||a<0)return{error:"고객 수는 0 이상의 정수, 월평균 매출은 0 이상으로 입력해 주세요."};return{mrr:c*a,arr:c*a*12};},format:function(r,api){return api.resultCard("월 반복매출 MRR",api.formatWon(r.mrr),"")+api.resultCard("연 환산 반복매출",api.formatWon(r.arr),"");}},{id:"annual-recurring-revenue",fields:[{"key":"mrr","label":"월 반복매출 MRR","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var m=Number(x.mrr);if(!Number.isFinite(m)||m<0)return{error:"월 반복매출은 0 이상으로 입력해 주세요."};return{arr:m*12,mrr:m};},format:function(r,api){return api.resultCard("연 반복매출 ARR",api.formatWon(r.arr),"")+api.resultCard("월 반복매출 MRR",api.formatWon(r.mrr),"");}},{id:"customer-payback-period",fields:[{"key":"cac","label":"고객획득비용 CAC","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"monthlyRevenue","label":"고객당 월 매출","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"grossMargin","label":"매출총이익률 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var c=Number(x.cac),r=Number(x.monthlyRevenue),m=Number(x.grossMargin)/100;if(![c,r,m].every(Number.isFinite)||c<0||r<0||m<=0||m>1)return{error:"마진율은 0보다 크고 100% 이하여야 합니다."};var profit=r*m;if(profit<=0)return{error:"월 고객총이익은 0보다 커야 합니다."};return{months:c/profit,monthlyGrossProfit:profit};},format:function(r,api){return api.resultCard("예상 회수기간",api.formatNumber(r.months,4)+"개월","")+api.resultCard("고객당 월 총이익",api.formatWon(r.monthlyGrossProfit),"");}},{id:"inventory-reorder-point",fields:[{"key":"dailyDemand","label":"일평균 판매량","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"leadTime","label":"조달기간 (일)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"safetyStock","label":"안전재고","type":"number","placeholder":"","default":"0","options":[],"raw":false}],hint:"재고가 계산된 재주문점에 도달하면 발주하는 단순 모델입니다.",compute:function(x){var d=Number(x.dailyDemand),l=Number(x.leadTime),s=Number(x.safetyStock);if(![d,l,s].every(Number.isFinite)||d<0||l<0||s<0)return{error:"입력값은 0 이상이어야 합니다."};return{point:d*l+s,leadDemand:d*l};},format:function(r,api){return api.resultCard("재주문점",api.formatNumber(r.point,4)+"개","")+api.resultCard("조달기간 예상수요",api.formatNumber(r.leadDemand,4)+"개","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
